<template>
  <view class="page">
    <!-- 顶部 Tabs -->
    <view class="tabs">
      <view
        v-for="(tab, index) in tabs"
        :key="index"
        class="tab"
        :class="{ active: currentTab === index }"
        @click="onTabChange(index)"
      >
        <text>{{ tab.label }}</text>
        <text v-if="getTabUnread(tab.status) > 0" class="tab-unread">{{ formatUnread(getTabUnread(tab.status)) }}</text>
      </view>
    </view>

    <!-- 列表区域 -->
    <scroll-view
      class="list-wrapper"
      scroll-y
      @scrolltolower="handleReachBottom"
    >
      <!-- 空状态 -->
      <view v-if="displayList.length === 0" class="empty">
        <image class="empty-img" src="/static/empty-order.png" mode="aspectFit" />
        <text class="empty-text">暂无订单</text>
      </view>

      <!-- 订单卡片 -->
      <view
        v-for="order in displayList"
        :key="order.id"
        class="card"
        @click="goDetail(order.id)"
      >
        <view class="row between row-top">
          <view class="top-left">
            <view class="type-badge" :class="order.type">{{ order.typeLabel }}</view>
            <view v-if="order.primaryTags && order.primaryTags.length" class="inline-tags">
              <view
                v-for="tag in order.primaryTags"
                :key="tag.key"
                class="tag-chip compact"
                :class="`tag-${tag.type}`"
              >
                <text v-if="tag.icon" class="chip-icon">{{ tag.icon }}</text>
                <text>{{ tag.text }}</text>
              </view>
            </view>
          </view>
          <view class="right-badges">
            <text v-if="getOrderUnread(order.id) > 0" class="chat-unread">{{ formatUnread(getOrderUnread(order.id)) }}</text>
            <text class="badge" :class="order.status">{{ statusMap[order.status] }}</text>
          </view>
        </view>
        <view class="row">
          <text class="place">{{ order.pickupLocation }}</text>
          <text class="place destination">
            <text class="destination-label">目的地：</text>{{ order.deliveryLocation || order.address }}
          </text>
        </view>
        <view v-if="order.secondaryTags && order.secondaryTags.length" class="row tag-row">
          <view
            v-for="tag in order.secondaryTags"
            :key="tag.key"
            class="tag-chip"
            :class="`tag-${tag.type}`"
          >
            <text v-if="tag.icon" class="chip-icon">{{ tag.icon }}</text>
            <text>{{ tag.text }}</text>
          </view>
        </view>
        <view class="remark-wrap">
          <text class="remark-label">备注：</text>
          <text class="remark-content">{{ order.remarkText || '无' }}</text>
        </view>
        <view class="row between footer-row">
          <view class="price-info">
            <text class="price-label">合计</text>
            <text class="price-amount">¥{{ Number(order.price || 0).toFixed(2) }}</text>
          </view>
          <text class="time">{{ order.publishedAt || order.createTime }}</text>
        </view>
        <view class="row actions-row">
          <view class="actions">
            <button
              v-if="order.status === 'completed'"
              class="btn btn-photo"
              size="mini"
              @click.stop="handleViewPhotos(order)"
            >
              送达照片
            </button>
            <button
              v-if="order.status === 'pending_accept' || order.status === 'pending_pickup' || order.status === 'delivering'"
              class="btn btn-cancel"
              size="mini"
              @click.stop="handleCancel(order.id)"
            >
              取消
            </button>
            <button
              v-if="order.status === 'completed'"
              class="btn btn-delete"
              size="mini"
              @click.stop="handleDelete(order.id)"
            >
              删除
            </button>
          </view>
        </view>
      </view>

      <!-- 加载状态 -->
      <view class="load-status">
        <text v-if="loadStatus === 'loading'">加载中...</text>
        <text v-else-if="loadStatus === 'noMore'">没有更多了</text>
        <text v-else>上拉加载更多</text>
      </view>
    </scroll-view>
  </view>
  <TheTabBar />
</template>

<script setup>
import TheTabBar from '@/components/TheTabBar.vue'
import { ref, computed } from 'vue'
import { onLoad, onPullDownRefresh, onShow } from '@dcloudio/uni-app'
import { useClientOrderStore } from '@/store/clientOrder'
import { buildVisualTags } from '@/utils/orderTags'

// 【修改点2】使用新的 store 名称
const store = useClientOrderStore()
const orderService = uniCloud.importObject('order-service')

const tabs = [
  { label: '全部', status: 'all' },
  { label: '待接单', status: 'pending_accept' },
  { label: '进行中', status: 'delivering' },
  { label: '已完成', status: 'completed' },
  { label: '异常单', status: 'abnormal' }
]

const statusMap = {
  pending_accept: '待接单',
  pending_pickup: '待取货',
  delivering: '配送中',
  completed: '已完成',
  cancelled: '已取消',
  abnormal: '异常单'
}

const currentTab = ref(0)
const pageSize = ref(20)
const loadStatus = ref('more') // 'more' | 'loading' | 'noMore'
const unreadByOrder = ref({})
const unreadByStatus = ref({})
const unreadTotal = ref(0)
const PRIMARY_TAG_TYPES = new Set(['urgent', 'delivery'])

const splitTags = (tags = []) => {
  const primary = []
  const secondary = []
  tags.forEach((tag) => {
    if (PRIMARY_TAG_TYPES.has(tag?.type)) {
      primary.push(tag)
    } else {
      secondary.push(tag)
    }
  })
  return { primary, secondary }
}

const resolveRemark = (order) => {
  const content = order?.content || {}
  const remark = content.remark || ''
  const desc = content.description || ''
  return String(remark || desc || '').trim()
}

// 【修改点3】重写 displayList 为计算属性，直接从 store 获取
const displayList = computed(() => {
  const status = tabs[currentTab.value].status
  // 使用 clientOrder store 提供的 getter
  const list = store.ordersByStatus(status)

  return list.map((o) => {
    const visualTags = buildVisualTags({
      rawTags: o.tags,
      content: o.content,
      requiredGender: o.content?.requiredRiderGender
    })
    const { primary, secondary } = splitTags(visualTags)
    return {
      ...o,
      primaryTags: primary,
      secondaryTags: secondary,
      remarkText: resolveRemark(o)
    }
  })
})

const refreshLoadStatus = () => {
  const paging = store.getPaging()
  if (paging.loading) {
    loadStatus.value = 'loading'
    return
  }
  loadStatus.value = paging.hasMore ? 'more' : 'noMore'
}

const loadData = async () => {
  if (loadStatus.value === 'loading') return
  loadStatus.value = 'loading'
  await store.reloadOrders({ pageSize: pageSize.value })
  await loadUnreadSummary()
  refreshLoadStatus()
}

const loadUnreadSummary = async () => {
  try {
    const res = await orderService.getMyOrderChatUnreadSummary({ role: 'user' })
    if (res?.code !== 0 || !res.data) return
    unreadByOrder.value = res.data.byOrder || {}
    unreadByStatus.value = res.data.byStatus || {}
    unreadTotal.value = Number(res.data.total || 0)
  } catch (e) {
    console.warn('加载聊天未读失败:', e)
  }
}

const getOrderUnread = (orderId) => Number(unreadByOrder.value?.[orderId] || 0)

const getTabUnread = (status) => {
  if (status === 'all') return unreadTotal.value
  if (status === 'delivering') {
    return Number(unreadByStatus.value?.pending_pickup || 0) + Number(unreadByStatus.value?.delivering || 0)
  }
  return Number(unreadByStatus.value?.[status] || 0)
}

const formatUnread = (count) => {
  const n = Number(count || 0)
  if (n <= 0) return ''
  return n > 99 ? '99+' : String(n)
}

const onTabChange = (index) => {
  currentTab.value = index
  // 切换 tab 时，computed 会自动更新数据
}

const handleReachBottom = () => {
  if (loadStatus.value === 'loading') return
  if (loadStatus.value === 'noMore') return
  loadStatus.value = 'loading'
  store.loadNextPage().finally(() => {
    refreshLoadStatus()
  })
}

const reloadCurrent = async () => {
  await store.reloadOrders({ pageSize: pageSize.value })
  refreshLoadStatus()
}

const handleCancel = async (id) => {
  uni.showModal({
    title: '确认取消',
    content: '确定要取消该订单吗？',
    success: async (res) => {
      if (res.confirm) {
        uni.showLoading({ title: '处理中...' })
        const ok = await store.cancelOrder(id)
        uni.hideLoading()
        if (ok) {
          uni.showToast({ title: '已取消', icon: 'success' })
        } else {
          // 错误提示已在 store 中处理
        }
      }
    }
  })
}

const handleDelete = async (id) => {
  uni.showModal({
    title: '确认删除',
    content: '删除后无法恢复，是否继续？',
    success: async (res) => {
      if (res.confirm) {
        uni.showLoading({ title: '处理中...' })
        const ok = await store.deleteOrder(id)
        uni.hideLoading()
        if (ok) {
          uni.showToast({ title: '已删除', icon: 'success' })
        } else {
          // 错误提示已在 store 中处理
        }
      }
    }
  })
}

const handleViewPhotos = (order) => {
  // 兼容不同字段名：delivery_images (数据库下划线命名) 或 deliveryImages (驼峰命名)
  const urls = order.content?.delivery_images || order.content?.deliveryImages || order.deliveryImages || (order.deliveryImage ? [order.deliveryImage] : [])
  
  if (!urls || !urls.length) {
    uni.showToast({ title: '暂无送达照片', icon: 'none' })
    return
  }
  uni.previewImage({ urls })
}

const goDetail = (id) => {
  uni.navigateTo({ url: `/pages/client/orders/detail?id=${id}` })
}

onPullDownRefresh(async () => {
  await reloadCurrent()
  await loadUnreadSummary()
  uni.stopPullDownRefresh()
})

onShow(async () => {
  await loadUnreadSummary()
})

onLoad(async () => {
  await loadData()
})
</script>

